          "case_id": 29,
          "source_page": 3,
          "source_text_path": "/tmp/war_ufo_science/hq_ocr/tesseract/029-59_214434_sp-16-7.18.1963-p0003.txt",
          "source_quote": "Our moon might not be less work to get to, since atmospheric braking to earth is possible, but would be very much easier to return from, while the energy requirements to go to and return from the surface of the earth might well be so high as to discourage interest, at least initially, Inter- estingly enough, even a normal high energy chemical rocket could make a trip from Mars to our moon at favorable times while carrying almost 10% of its gross weight in payload.",
          "claim_type": "object_description",
          "witness_label": null,
          "directness": "not_assessed",
          "independence_status": "not_assessed",
          "time_stated": null,
          "location_stated": "moon",
